use std::mem::{ManuallyDrop, MaybeUninit};

struct FixedStack<T, const N: usize> {
    data: [ManuallyDrop<T>; N],
    len: usize,
}

impl<T, const N: usize> FixedStack<T, N> {
    fn new() -> Self {
        FixedStack {
            data: unsafe { MaybeUninit::uninit().assume_init() },
            len: 0,
        }
    }
    fn push(&mut self, val: T) -> bool {
        if self.len >= N { return false; }
        self.data[self.len] = ManuallyDrop::new(val);
        self.len += 1;
        true
    }
    fn pop(&mut self) -> Option<T> {
        if self.len == 0 { return None; }
        self.len -= 1;
        Some(unsafe { ManuallyDrop::take(&mut self.data[self.len]) })
    }
}

impl<T, const N: usize> Drop for FixedStack<T, N> {
    fn drop(&mut self) {
        for i in 0..self.len {
            unsafe { ManuallyDrop::drop(&mut self.data[i]); }
        }
    }
}

fn main() {
    let mut stack: FixedStack<String, 4> = FixedStack::new();
    stack.push(String::from("a"));
    stack.push(String::from("b"));
    println!("popped: {:?}", stack.pop());
