use std::rc::Rc;
use std::mem;

/// Produce a raw pointer that logically owns one Rc ref-count increment.
fn into_raw_rc(rc: Rc<i32>) -> *const i32 {
    Rc::into_raw(rc) // consumes rc (like forget) and returns raw ptr
}

/// Reconstruct the Rc, decrementing the count on drop.
unsafe fn from_raw_rc(ptr: *const i32) -> Rc<i32> {
    Rc::from_raw(ptr)
}

fn main() {
    let rc = Rc::new(42);
    let rc2 = Rc::clone(&rc);
    let ptr = into_raw_rc(rc2); // rc2 consumed; count stays at 2
    println!("count: {}", Rc::strong_count(&rc)); // 2
    let recovered = unsafe { from_raw_rc(ptr) };
    println!("recovered: {}", *recovered);
    // recovered drops: count goes to 1
}
